const items = $input.all();

let totalPositive = 0;
let totalNeutral = 0;
let totalNegative = 0;
const themes = {};
const flaggedAccounts = [];

for (const item of items) {
  const text = item.json.feedback_text || item.json.comment || item.json.description || '';
  const score = item.json.nps_score || item.json.rating || item.json.satisfaction_score || 5;
  const source = item.json.source || 'unknown';
  const account = item.json.account_name || item.json.company || 'Unknown';

  // Simple sentiment classification
  let sentiment = 'neutral';
  if (score >= 8 || score >= 4.5) { sentiment = 'positive'; totalPositive++; }
  else if (score <= 5 || score <= 2) { sentiment = 'negative'; totalNegative++; }
  else { totalNeutral++; }

  // Theme extraction (keyword-based)
  const keywords = {
    'onboarding': ['onboarding', 'setup', 'getting started', 'implementation'],
    'performance': ['slow', 'fast', 'speed', 'performance', 'loading'],
    'support': ['support', 'help', 'response time', 'ticket'],
    'features': ['feature', 'missing', 'wish', 'roadmap', 'integration'],
    'pricing': ['price', 'cost', 'expensive', 'value', 'billing']
  };

  const lowerText = text.toLowerCase();
  for (const [theme, words] of Object.entries(keywords)) {
    if (words.some(w => lowerText.includes(w))) {
      themes[theme] = (themes[theme] || 0) + 1;
    }
  }

  if (sentiment === 'negative' && account !== 'Unknown') {
    flaggedAccounts.push({ account, source, score, snippet: text.substring(0, 100) });
  }
}

const total = totalPositive + totalNeutral + totalNegative;
const topThemes = Object.entries(themes).sort((a, b) => b[1] - a[1]).slice(0, 5);

return [{
  json: {
    total_feedback: total,
    positive: totalPositive,
    neutral: totalNeutral,
    negative: totalNegative,
    sentiment_score: total > 0 ? Math.round((totalPositive / total) * 100) : 0,
    top_themes: topThemes.map(([theme, count]) => `${theme} (${count})`),
    flagged_accounts: flaggedAccounts.slice(0, 10),
    period: `${$now.minus(7, 'days').format('MMM dd')} - ${$now.format('MMM dd, yyyy')}`
  }
}];

